// ── Colour helpers ────────────────────────────────────────────────────────────
// Palette is stored as RGB565 (matches display_ili9341 HW format).
// Convert to MiniWin's mw_hal_lcd_colour_t (0x00RRGGBB) at draw time.
static inline mw_hal_lcd_colour_t c565(uint16_t c) {
    uint8_t r5 = (c >> 11) & 0x1F;
    uint8_t g6 = (c >> 5)  & 0x3F;
    uint8_t b5 =  c        & 0x1F;
    return ((uint32_t)((r5 << 3) | (r5 >> 2)) << 16)
         | ((uint32_t)((g6 << 2) | (g6 >> 4)) << 8)
         |  (uint32_t)((b5 << 3) | (b5 >> 2));
}

