// ── App list ──────────────────────────────────────────────────────────────────
#define MAX_APPS 32
struct BbApp { char name[32]; char path[128]; };
static BbApp s_apps[MAX_APPS];
static int   s_napp = 0;

static void scan_apps() {
    s_napp = 0;
    int n = kitt.app_list_count();
    for (int i = 0; i < n && s_napp < MAX_APPS; i++) {
        KITT::app_entry_t e;
        kitt.app_get_entry(i, &e);
        strncpy(s_apps[s_napp].name, e.name, sizeof(s_apps[0].name) - 1);
        strncpy(s_apps[s_napp].path, e.path, sizeof(s_apps[0].path) - 1);
        s_napp++;
    }
}

