// ── Touch state (shared between message function and tap dispatch) ─────────────
static int16_t  s_touch_start_x = 0;
static int16_t  s_touch_start_y = 0;
static int16_t  s_last_x = 0;
static int16_t  s_last_y = 0;
static uint32_t s_debounce_ms = 0;

// ── MiniWin root window callbacks ─────────────────────────────────────────────

void mw_user_root_paint_function(const mw_gl_draw_info_t *draw_info) {
#ifdef PURR_BBUI_TARGET_TOUCH
    if (s_state == STATE_HOME) draw_home(draw_info);
    else                       draw_drawer(draw_info);
#else
    (void)draw_info;
#endif
}

void mw_user_root_message_function(const mw_message_t *message) {
#ifdef PURR_BBUI_TARGET_TOUCH
    if (message->message_id == MW_TOUCH_DOWN_MESSAGE) {
        s_touch_start_x = (int16_t)(message->message_data >> 16);
        s_touch_start_y = (int16_t)(message->message_data & 0xFFFF);
        s_last_x = s_touch_start_x;
        s_last_y = s_touch_start_y;

    } else if (message->message_id == MW_TOUCH_DRAG_MESSAGE) {
        s_last_x = (int16_t)(message->message_data >> 16);
        s_last_y = (int16_t)(message->message_data & 0xFFFF);

    } else if (message->message_id == MW_TOUCH_UP_MESSAGE) {
        int16_t  dx  = s_last_x - s_touch_start_x;
        int16_t  dy  = s_last_y - s_touch_start_y;
        uint32_t now = millis();

        if (abs(dy) >= 50 && abs(dy) > abs(dx)) {
            if (dy < 0 && s_state == STATE_HOME) {
                s_state = STATE_DRAWER;
                mw_paint_all();
            } else if (dy > 0 && s_state == STATE_DRAWER) {
                s_state = STATE_HOME;
                mw_paint_all();
            }
        } else if (abs(dx) <= 15 && abs(dy) <= 15 && now - s_debounce_ms >= 250) {
            s_debounce_ms = now;
            int id = hit_test(s_touch_start_x, s_touch_start_y);
            if (id >= 0) on_tap(id);
        }
    }
#else
    (void)message;
#endif
}

void mw_user_init(void) {
#ifdef PURR_BBUI_TARGET_TOUCH
    led_init();
    scan_apps();
    Serial.printf("[bbui] mw_user_init  apps=%d\n", s_napp);

#else
    Serial.println("[bbui] T-Deck stub — ST7789 + key HAL pending");
#endif
}

// ── MiniWin task ──────────────────────────────────────────────────────────────
static void miniwin_task(void *) {
    Serial.println("[bbui] MiniWin starting");
    mw_init();

    for (;;) {
        while (mw_process_message()) {}
        mw_paint_all();   // render all dirty windows — matches sim loop behaviour
        led_heartbeat();
        vTaskDelay(pdMS_TO_TICKS(MW_TICK_PERIOD_MS));
    }
}

void blackberry_ui_start() {
    xTaskCreatePinnedToCore(miniwin_task, "miniwin", 12288, nullptr, 3, nullptr, 1);
}

#endif  // PURR_HAS_BLACKBERRY_UI
